"use strict";(self.webpackChunkrgbds_www=self.webpackChunkrgbds_www||[]).push([[9337],{28453:(e,a,s)=>{s.d(a,{R:()=>l,x:()=>i});var t=s(96540);const n={},o=t.createContext(n);function l(e){const a=t.useContext(o);return t.useMemo((function(){return"function"==typeof e?e(a):{...a,...e}}),[a,e])}function i(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:l(e.components),t.createElement(o.Provider,{value:a},e.children)}},30701:(e,a,s)=>{s.r(a),s.d(a,{assets:()=>d,contentTitle:()=>c,default:()=>h,frontMatter:()=>i,metadata:()=>t,toc:()=>r});const t=JSON.parse('{"id":"rgbgfx.1","title":"rgbgfx(1) \u2014 Game Boy graphics converter","description":"","source":"@site/versioned_docs/version-v1.0.0/rgbgfx.1.md","sourceDirName":".","slug":"/rgbgfx.1","permalink":"/docs/v1.0.0/rgbgfx.1","draft":false,"unlisted":false,"editUrl":"https://github.com/gbdev/rgbds/edit/master/man/rgbgfx.1","tags":[],"version":"v1.0.0","frontMatter":{},"sidebar":"nav","previous":{"title":"RGBFIX","permalink":"/docs/v1.0.0/rgbfix.1"},"next":{"title":"History","permalink":"/docs/v1.0.0/rgbds.7"}}');var n=s(74848),o=s(28453);const l='<section class="Sh">\n<h2 class="Sh" id="SYNOPSIS"><a class="permalink" href="#SYNOPSIS">SYNOPSIS</a></h2>\n<table class="Nm">\n  <tr>\n    <td><code class="Nm">rgbgfx</code></td>\n    <td>[<code class="Fl"><a href="#C">-C</a><a href="#m">m</a><a href="#h">h</a><a href="#O">O</a><a href="#u">u</a><a href="#V">V</a><a href="#w">w</a><a href="#X">X</a><a href="#Y">Y</a><a href="#Z">Z</a></code>] [<code class="Fl"><a href="#v">-v</a></code>\n      [<code class="Fl"><a href="#v">-v</a></code> <span class="No">...</span>]]\n      [<code class="Fl"><a href="#a">-a</a></code> <var class="Ar">attrmap</var> |\n      <code class="Fl"><a href="#A">-A</a></code>] [<code class="Fl"><a href="#b">-b</a></code>\n      <var class="Ar">base_ids</var>] [<code class="Fl"><a href="#c">-c</a></code>\n      <var class="Ar">pal_spec</var>] [<code class="Fl">--color</code>\n      <var class="Ar">when</var>] [<code class="Fl"><a href="#d">-d</a></code>\n      <var class="Ar">depth</var>] [<code class="Fl"><a href="#i">-i</a></code>\n      <var class="Ar">input_tiles</var>] [<code class="Fl"><a href="#L">-L</a></code>\n      <var class="Ar">slice</var>] [<code class="Fl"><a href="#l">-l</a></code>\n      <var class="Ar">base_pal</var>] [<code class="Fl"><a href="#N">-N</a></code>\n      <var class="Ar">nb_tiles</var>] [<code class="Fl"><a href="#n">-n</a></code>\n      <var class="Ar">nb_pals</var>] [<code class="Fl"><a href="#o">-o</a></code>\n      <var class="Ar">out_file</var>] [<code class="Fl"><a href="#p">-p</a></code>\n      <var class="Ar">pal_file</var> | <code class="Fl"><a href="#P">-P</a></code>]\n      [<code class="Fl"><a href="#q">-q</a></code> <var class="Ar">pal_map</var> |\n      <code class="Fl"><a href="#Q">-Q</a></code>] [<code class="Fl"><a href="#r">-r</a></code>\n      <var class="Ar">width</var>] [<code class="Fl"><a href="#s">-s</a></code>\n      <var class="Ar">nb_colors</var>] [<code class="Fl"><a href="#t">-t</a></code>\n      <var class="Ar">tilemap</var> | <code class="Fl"><a href="#T">-T</a></code>]\n      [<code class="Fl"><a href="#W">-W</a></code> <var class="Ar">warning</var>]\n      [<code class="Fl"><a href="#x">-x</a></code> <var class="Ar">quantity</var>]\n      <var class="Ar">file</var></td>\n  </tr>\n</table>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="DESCRIPTION"><a class="permalink" href="#DESCRIPTION">DESCRIPTION</a></h2>\n<p class="Pp">The <code class="Nm">rgbgfx</code> program converts PNG images\n    into data suitable for display on the Game Boy and Game Boy Color, or\n    vice-versa.</p>\n<p class="Pp" id="squares">The main function of <code class="Nm">rgbgfx</code>\n    is to divide the input PNG into 8&#x00D7;8 pixel\n    <a class="permalink" href="#squares"><i class="Em">squares</i></a>, convert\n    each of those squares into 1bpp or 2bpp tile data, and save all of the tile\n    data in a file. It also has options to generate a tile map, attribute map,\n    and/or palette set as well; more on that and how the conversion process can\n    be tweaked below.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="ARGUMENTS"><a class="permalink" href="#ARGUMENTS">ARGUMENTS</a></h2>\n<p class="Pp"><code class="Nm">rgbgfx</code> accepts the usual short and long\n    options, such as <code class="Fl">-V</code> and\n    <code class="Fl">--version</code>. Options later in the command line\n    override those set earlier, except for when duplicate options are considered\n    an error. Options can be abbreviated as long as the abbreviation is\n    unambiguous: <code class="Fl">--verb</code> is\n    <code class="Fl">--verbose</code>, but <code class="Fl">--ver</code> is\n    invalid because it could also be <code class="Fl">--version</code>.</p>\n<p class="Pp">Unless otherwise noted, passing\n    &#x2018;<code class="Li">-</code>&#x2019; (a single dash) as a file name\n    makes <code class="Nm">rgbgfx</code> use standard input (for input files) or\n    standard output (for output files). To suppress this behavior, and open a\n    file in the current directory actually called\n    &#x2018;<code class="Li">-</code>&#x2019;, pass\n    &#x2018;<code class="Li">./-</code>&#x2019; instead. Using standard input or\n    output for more than one file in a single command may produce unexpected\n    results.</p>\n<p class="Pp"><code class="Nm">rgbgfx</code> accepts decimal, hexadecimal,\n    octal, and binary for numeric option arguments. Decimal numbers are written\n    as usual; hexadecimal numbers must be prefixed with either\n    &#x2018;<code class="Li">$</code>&#x2019; or\n    &#x2018;<code class="Li">0x</code>&#x2019;; octal numbers must be prefixed\n    with either &#x2018;<code class="Li">&amp;</code>&#x2019; or\n    &#x2018;<code class="Li">0o</code>&#x2019;; and binary numbers must be\n    prefixed with either &#x2018;<code class="Li">%</code>&#x2019; or\n    &#x2018;<code class="Li">0b</code>&#x2019;. (The prefixes\n    &#x2018;<code class="Li">$</code>&#x2019; and\n    &#x2018;<code class="Li">&amp;</code>&#x2019; will likely need escaping or\n    quoting to avoid being interpreted by the shell.) Leading zeros (after the\n    base prefix, if any) are accepted, and letters are not case-sensitive. For\n    example, all of these are equivalent:\n    &#x2018;<code class="Li">42</code>&#x2019;,\n    &#x2018;<code class="Li">042</code>&#x2019;,\n    &#x2018;<code class="Li">0x2A</code>&#x2019;,\n    &#x2018;<code class="Li">0X2A</code>&#x2019;,\n    &#x2018;<code class="Li">0x2a</code>&#x2019;,\n    &#x2018;<code class="Li">&amp;52</code>&#x2019;,\n    &#x2018;<code class="Li">0o52</code>&#x2019;,\n    &#x2018;<code class="Li">0O052</code>&#x2019;,\n    &#x2018;<code class="Li">0b00101010</code>&#x2019;,\n    &#x2018;<code class="Li">0B101010</code>&#x2019;.</p>\n<p class="Pp">The following options are accepted:</p>\n<dl class="Bl-tag">\n  <dt id="a"><a class="permalink" href="#a"><code class="Fl">-a</code></a>\n    <var class="Ar">attrmap</var>, <code class="Fl">--attr-map</code>\n    <var class="Ar">attrmap</var></dt>\n  <dd>Generate an attribute map, which is a file containing tile\n      &#x201C;attributes&#x201D;. For each square of the input image, its\n      corresponding attribute map byte contains the mirroring bits (if\n      <code class="Fl">-m</code> was specified), the bank bit (see\n      <code class="Fl">-N</code>), and the palette index. See\n      <a class="Lk" href="https://gbdev.io/pandocs/Tile_Maps#bg-map-attributes-cgb-mode-only">Pan\n      Docs</a> for the individual bytes\' format. The output is written just like\n      the tile map (see <code class="Fl">-t</code>), follows the same order\n      (<code class="Fl">-Z</code>), and has the same size.</dd>\n  <dt id="A"><a class="permalink" href="#A"><code class="Fl">-A</code></a>,\n    <code class="Fl">--auto-attr-map</code></dt>\n  <dd>Same as <code class="Fl">-a</code> <var class="Ar">base_path</var>.attrmap\n      (see <a class="Sx" href="#Automatic_output_paths">Automatic output\n      paths</a>).</dd>\n  <dt id="B"><a class="permalink" href="#B"><code class="Fl">-B</code></a>\n    <var class="Ar">color</var>, <code class="Fl">--background-color</code>\n    <var class="Ar">color</var></dt>\n  <dd>Set a background color to be omitted from output. Colors are accepted in\n      &#x2018;<code class="Li">#rgb</code>&#x2019; or\n      &#x2018;<code class="Li">#rrggbb</code>&#x2019; format, or as\n      &#x2018;<code class="Li">transparent</code>&#x2019;. Input tiles which are\n      entirely the specified background color are ignored and will not be output\n      in tile data file. The tilemap, atrribute map, or palette map files\n      <a class="permalink" href="#will"><i class="Em" id="will">will</i></a> use\n      placeholder values where background tiles were. If a background color is\n      specified, it cannot be used within tiles which are not ignored.</dd>\n  <dt id="b"><a class="permalink" href="#b"><code class="Fl">-b</code></a>\n    <var class="Ar">base_ids</var>, <code class="Fl">--base-tiles</code>\n    <var class="Ar">base_ids</var></dt>\n  <dd>Set the base IDs for tile map output. <var class="Ar">base_ids</var>\n      should be one or two numbers between 0 and 255, separated by a comma; they\n      are for bank 0 and bank 1 respectively. Both default to 0.</dd>\n  <dt id="C"><a class="permalink" href="#C"><code class="Fl">-C</code></a>,\n    <code class="Fl">--color-curve</code></dt>\n  <dd>When generating palettes, use a color curve mimicking the Game Boy Color\'s\n      screen. The resulting colors may look closer to the input image\'s\n      <a class="permalink" href="#on"><b class="Sy" id="on">on hardware and\n      accurate emulators</b></a>.</dd>\n  <dt id="c"><a class="permalink" href="#c"><code class="Fl">-c</code></a>\n    <var class="Ar">pal_spec</var>, <code class="Fl">--colors</code>\n    <var class="Ar">pal_spec</var></dt>\n  <dd>Use the specified color palettes instead of having\n      <code class="Nm">rgbgfx</code> automatically determine some.\n      <var class="Ar">pal_spec</var> can be one of the following:\n    <dl class="Bl-tag">\n      <dt id="inline"><a class="permalink" href="#inline"><b class="Sy">inline\n        palette spec</b></a></dt>\n      <dd>If <var class="Ar">pal_spec</var> begins with a hash character\n          &#x2018;<code class="Li">#</code>&#x2019;, it is treated as an inline\n          palette specification. It should contain a comma-separated list of\n          hexadecimal colors, each beginning with a hash. Colors are accepted in\n          &#x2018;<code class="Li">#rgb</code>&#x2019; or\n          &#x2018;<code class="Li">#rrggbb</code>&#x2019; format. To leave one\n          or more gaps in the palette,\n          &#x2018;<code class="Li">#none</code>&#x2019; can be used instead of\n          any color. Palettes must be separated by a colon or semicolon (the\n          latter may require quoting to avoid special handling by the shell),\n          and spaces are allowed around colons, semicolons and commas; trailing\n          commas and semicolons are allowed. See\n          <a class="Sx" href="#EXAMPLES">EXAMPLES</a> for an example of an\n          inline palette specification.</dd>\n      <dt id="embedded"><a class="permalink" href="#embedded"><b class="Sy">embedded\n        palette spec</b></a></dt>\n      <dd>If <var class="Ar">pal_spec</var> is the case-insensitive word\n          <code class="Cm">embedded</code>, then the first four colors of the\n          input PNG\'s embedded palette are used. It is an error if the PNG is\n          not indexed, or if colors other than these 4 are used. (This is\n          different from the default behavior of indexed PNGs, as then unused\n          entries in the embedded palette are ignored, whereas they are not with\n          <code class="Fl">-c</code> <code class="Cm">embedded</code>).</dd>\n      <dt id="DMG"><a class="permalink" href="#DMG"><b class="Sy">DMG palette\n        spec</b></a></dt>\n      <dd>If <var class="Ar">pal_spec</var> starts with case-insensitive\n          <code class="Cm">dmg=</code>, then the following two-digit hexadecimal\n          number specifies four grayscale DMG color indexes. The number\n          functions like the DMG\'s $FF47\n          <a class="permalink" href="#BGP"><b class="Sy" id="BGP">BGP</b></a>\n          register (see\n          <a class="Lk" href="https://gbdev.io/pandocs/Palettes.html">Pan\n          Docs</a> for more information): the low two bits 0-1 specify which\n          gray shade goes in color index 0, the next two bits 2-3 specify which\n          gray shade goes in color index 1, and so on. Gray shade 0 is the\n          lightest (white), 3 is the darkest (black). If\n          <var class="Ar">pal_spec</var> is the case-insensitive word\n          <code class="Cm">dmg</code>, then it acts like\n          <code class="Cm">dmg=E4</code>, i.e. the darkest gray will end up in\n          color index 0, and so on. The same gray shade cannot go in two color\n          indexes. To specify a DMG palette, the input PNG must have all its\n          colors in shades of gray, without any transparent colors.</dd>\n      <dt id="automatic"><a class="permalink" href="#automatic"><b class="Sy">automatic\n        palette generation</b></a></dt>\n      <dd>If <var class="Ar">pal_spec</var> is the case-insensitive word\n          <code class="Cm">auto</code>, then a palette is automatically\n          generated using the procedure described in\n          <a class="Sx" href="#PALETTE_GENERATION">PALETTE GENERATION</a>. This\n          is the default behavior if <code class="Fl">-c</code> was not\n          specified.</dd>\n      <dt id="external"><a class="permalink" href="#external"><b class="Sy">external\n        palette spec</b></a></dt>\n      <dd>Otherwise, <var class="Ar">pal_spec</var> is assumed to be an external\n          palette specification. The expected format is\n          &#x2018;<code class="Li">format:path</code>&#x2019;, where\n          <var class="Ar">path</var> is a path to a file\n          (&#x2018;<code class="Li">-</code>&#x2019; is not treated specially),\n          which will be processed according to the <var class="Ar">format</var>.\n          See <a class="Sx" href="#PALETTE_SPECIFICATION_FORMATS">PALETTE\n          SPECIFICATION FORMATS</a> for a list of formats and their\n          descriptions.</dd>\n    </dl>\n  </dd>\n  <dt id="color"><a class="permalink" href="#color"><code class="Fl">--color</code></a>\n    <var class="Ar">when</var></dt>\n  <dd>Specify when to highlight warning and error messages with color:\n      &#x2018;<code class="Li">always</code>&#x2019;,\n      &#x2018;<code class="Li">never</code>&#x2019;, or\n      &#x2018;<code class="Li">auto</code>&#x2019;.\n      &#x2018;<code class="Li">auto</code>&#x2019; determines whether to use\n      colors based on the\n      &#x2018;<code class="Li"><a class="Lk" href="https://no-color.org/">NO_COLOR</a></code>&#x2019;\n      or\n      &#x2018;<code class="Li"><a class="Lk" href="https://force-color.org/">FORCE_COLOR</a></code>&#x2019;\n      environment variables, or whether the output is to a TTY.</dd>\n  <dt id="d"><a class="permalink" href="#d"><code class="Fl">-d</code></a>\n    <var class="Ar">depth</var>, <code class="Fl">--depth</code>\n    <var class="Ar">depth</var></dt>\n  <dd>Set the bit depth of the output tile data, in bits per pixel (bpp), either\n      1 or 2 (the default). This changes how tile data is output, and the\n      maximum number of colors per palette (2 and 4 respectively).</dd>\n  <dt id="h"><a class="permalink" href="#h"><code class="Fl">-h</code></a>,\n    <code class="Fl">--help</code></dt>\n  <dd>Print help text for the program and exit.</dd>\n  <dt id="i"><a class="permalink" href="#i"><code class="Fl">-i</code></a>\n    <var class="Ar">input_tiles</var>, <code class="Fl">--input-tileset</code>\n    <var class="Ar">input_tiles</var></dt>\n  <dd>Use the specified input tiles in addition to having\n      <code class="Nm">rgbgfx</code> automatically determine some. The input\n      tiles will always be first in the <code class="Fl">-o</code> image output,\n      and will always get the first IDs in the <code class="Fl">-t</code>\n      tilemap output. <var class="Ar">input_tiles</var> must contain 1bpp or\n      2bpp tile data (whichever matches the <code class="Fl">-d</code>\n      <span class="No">option used here</span>), as could be previously\n      generated with the <code class="Fl">-o</code> option.\n    <p class="Pp" id="not">If the <code class="Fl">-o</code> option is also\n        specified, then the input tiles will be assigned the first tile IDs, and\n        any tiles from the input image that are not in the input tileset will be\n        assigned subsequent IDs. But if the <code class="Fl">-o</code> option is\n        <a class="permalink" href="#not"><i class="Em">not</i></a> specified,\n        then the tile map can\n        <a class="permalink" href="#only"><i class="Em" id="only">only</i></a>\n        use tiles from the input tileset. Using <code class="Fl">-o</code> with\n        <code class="Fl">-i</code> is useful if you want to precisely control\n        the tile IDs of its tile map. Using <code class="Fl">-i</code> alone is\n        more useful if you want several images to use a subset of shared\n      tiles.</p>\n    <p class="Pp" id="strongly">If the image will use more than one color\n        palette, it is\n        <a class="permalink" href="#strongly"><i class="Em">strongly</i></a>\n        advised to generate the palette set along with the input tile data, and\n        pass <code class="Fl">-c</code>\n        <code class="Cm">gbc:</code><var class="Ar">input_palette</var> along\n        with <code class="Fl">-i</code> <var class="Ar">input_tiles</var>. This\n        is because <code class="Nm">rgbgfx</code> might not generate the same\n        palette set for this image as it did for its input tileset.</p>\n    <p class="Pp">See <a class="Sx" href="#EXAMPLES">EXAMPLES</a> for examples\n        of how to use this option.</p>\n    <p class="Pp">This option is ignored in\n        <a class="Sx" href="#REVERSE_MODE">REVERSE MODE</a>.</p>\n  </dd>\n  <dt id="L"><a class="permalink" href="#L"><code class="Fl">-L</code></a>\n    <var class="Ar">slice</var>, <code class="Fl">--slice</code>\n    <var class="Ar">slice</var></dt>\n  <dd>Only process a given rectangle of the image. This is useful for example if\n      the input image is a sheet of some sort, and you want to convert each cel\n      individually. The default is to process the whole image as-is.\n    <p class="Pp"><var class="Ar">slice</var> must be two number pairs,\n        separated by a colon. The numbers must be separated by commas; space is\n        allowed around all punctuation. The first number pair specifies the X\n        and Y coordinates of the top-left pixel that will be processed (anything\n        above it or to its left will be ignored). The second number pair\n        specifies how many tiles to process horizontally and vertically,\n        respectively.</p>\n    <p class="Pp" id="is"><code class="Fl">-L</code>\n        <a class="permalink" href="#is"><b class="Sy">is ignored in reverse\n        mode</b></a>, <span class="No">no padding is inserted</span>.</p>\n  </dd>\n  <dt id="l"><a class="permalink" href="#l"><code class="Fl">-l</code></a>\n    <var class="Ar">base_pal</var>, <code class="Fl">--base-palette</code>\n    <var class="Ar">base_pal</var></dt>\n  <dd>Set the base ID for attribute map and palette map output.\n      <var class="Ar">base_pal</var> should be a number between 0 and 255. It\n      defaults to 0.</dd>\n  <dt id="m"><a class="permalink" href="#m"><code class="Fl">-m</code></a>,\n    <code class="Fl">--mirror-tiles</code></dt>\n  <dd>Deduplicate tiles that are horizontally and/or vertically symmetrical\n      mirror images of each other. Only one of each unique tile will be saved in\n      the tile data file, with mirror images counting as duplicates. Useful with\n      a tile map and attribute map together (see <code class="Fl">-a</code> and\n      <code class="Fl">-t</code>) to keep track of the duplicated tiles and the\n      dimension(s) mirrored. Implies <code class="Fl">-u</code>. Equivalent to\n      <code class="Fl">-XY</code>.</dd>\n  <dt id="N"><a class="permalink" href="#N"><code class="Fl">-N</code></a>\n    <var class="Ar">nb_tiles</var>, <code class="Fl">--nb-tiles</code>\n    <var class="Ar">nb_tiles</var></dt>\n  <dd>Set a maximum number of tiles that can be placed in each VRAM bank.\n      <var class="Ar">nb_tiles</var> should be one or two numbers between 0 and\n      256, separated by a comma; if the latter is omitted, it defaults to 0.\n      Setting either number to 0 prevents any tiles from being output in that\n      bank.\n    <p class="Pp">If more tiles are generated than can fit in the two banks\n        combined, <code class="Nm">rgbgfx</code> will abort. If\n        <code class="Fl">-N</code> is not specified, no limit will be set on the\n        amount of tiles placed in bank 0, and tiles will not be placed in bank\n        1.</p>\n  </dd>\n  <dt id="n"><a class="permalink" href="#n"><code class="Fl">-n</code></a>\n    <var class="Ar">nb_pals</var>, <code class="Fl">--nb-palettes</code>\n    <var class="Ar">nb_pals</var></dt>\n  <dd>Abort if more than <var class="Ar">nb_pals</var> palettes are generated.\n      This may not be more than 256.\n    <p class="Pp">Note that attribute map output only has 3 bits for the palette\n        ID, so a limit higher than 8 may yield incomplete data unless relying on\n        a palette map (see <code class="Fl">-q</code>).</p>\n  </dd>\n  <dt id="O"><a class="permalink" href="#O"><code class="Fl">-O</code></a>,\n    <code class="Fl">--group-outputs</code></dt>\n  <dd>Sets the &#x2018;base path&#x2019; to be the output tile data path from\n      <code class="Fl">-o</code> instead of the input image path (see\n      <a class="Sx" href="#Automatic_output_paths">Automatic output\n    paths</a>).</dd>\n  <dt id="o"><a class="permalink" href="#o"><code class="Fl">-o</code></a>\n    <var class="Ar">out_file</var>, <code class="Fl">--output</code>\n    <var class="Ar">out_file</var></dt>\n  <dd>Output the tile data in native 2bpp format or in 1bpp (depending on\n      <code class="Fl">-d</code>) to this file.</dd>\n  <dt id="p"><a class="permalink" href="#p"><code class="Fl">-p</code></a>\n    <var class="Ar">pal_file</var>, <code class="Fl">--palette</code>\n    <var class="Ar">pal_file</var></dt>\n  <dd>Output the image\'s palette set to this file.</dd>\n  <dt id="P"><a class="permalink" href="#P"><code class="Fl">-P</code></a>,\n    <code class="Fl">--auto-palette</code></dt>\n  <dd>Same as <code class="Fl">-p</code> <var class="Ar">base_path</var>.pal\n      (see <a class="Sx" href="#Automatic_output_paths">Automatic output\n      paths</a>).</dd>\n  <dt id="q"><a class="permalink" href="#q"><code class="Fl">-q</code></a>\n    <var class="Ar">pal_map</var>, <code class="Fl">--palette-map</code>\n    <var class="Ar">pal_map</var></dt>\n  <dd>Output the image\'s palette map to this file. This is useful if the input\n      image contains more than 8 palettes, as the attribute map only contains\n      the lower 3 bits of the palette indices.</dd>\n  <dt id="Q"><a class="permalink" href="#Q"><code class="Fl">-Q</code></a>,\n    <code class="Fl">--auto-palette-map</code></dt>\n  <dd>Same as <code class="Fl">-q</code> <var class="Ar">base_path</var>.palmap\n      (see <a class="Sx" href="#Automatic_output_paths">Automatic output\n      paths</a>).</dd>\n  <dt id="r"><a class="permalink" href="#r"><code class="Fl">-r</code></a>\n    <var class="Ar">width</var>, <code class="Fl">--reverse</code>\n    <var class="Ar">width</var></dt>\n  <dd>Switches <code class="Nm">rgbgfx</code> into\n      &#x201C;<a class="permalink" href="#reverse"><b class="Sy" id="reverse">reverse</b></a>&#x201D;\n      mode. In this mode, instead of converting a PNG image into Game Boy data,\n      <code class="Nm">rgbgfx</code> will attempt to reverse the process, and\n      render Game Boy data into an image. See\n      <a class="Sx" href="#REVERSE_MODE">REVERSE MODE</a> below for details.\n    <p class="Pp"><var class="Ar">width</var> is the width of the image to\n        generate, in tiles. <code class="Fl">-r</code>\n        <code class="Fl">-0</code> chooses a width to make the image as square\n        as possible. This is useful if you do not know the original width.</p>\n  </dd>\n  <dt id="s"><a class="permalink" href="#s"><code class="Fl">-s</code></a>\n    <var class="Ar">nb_colors</var>, <code class="Fl">--palette-size</code>\n    <var class="Ar">nb_colors</var></dt>\n  <dd>Specify how many colors each palette contains, including the transparent\n      one if any. <var class="Ar">nb_colors</var> cannot be more than\n      &#x2018;<code class="Li">1 &lt;&lt;\n      <var class="Ar">depth</var></code>&#x2019; (see\n      <code class="Fl">-d</code>).</dd>\n  <dt id="t"><a class="permalink" href="#t"><code class="Fl">-t</code></a>\n    <var class="Ar">tilemap</var>, <code class="Fl">--tilemap</code>\n    <var class="Ar">tilemap</var></dt>\n  <dd>Generate a file of tile indices. For each square of the input image, its\n      corresponding tile map byte contains the index of the associated tile in\n      the tile data file. The IDs wrap around from 255 back to 0, and do not\n      include the bank bit; use <code class="Fl">-a</code> for that. Useful in\n      combination with <code class="Fl">-u</code> and/or\n      <code class="Fl">-m</code> to keep track of duplicate tiles.</dd>\n  <dt id="T"><a class="permalink" href="#T"><code class="Fl">-T</code></a>,\n    <code class="Fl">--auto-tilemap</code></dt>\n  <dd>Same as <code class="Fl">-t</code> <var class="Ar">base_path</var>.tilemap\n      (see <a class="Sx" href="#Automatic_output_paths">Automatic output\n      paths</a>).</dd>\n  <dt id="u"><a class="permalink" href="#u"><code class="Fl">-u</code></a>,\n    <code class="Fl">--unique-tiles</code></dt>\n  <dd>Deduplicate identical tiles. Only one of each unique tile will be saved in\n      the tile data file. Useful with a tile map (see\n      <code class="Fl">-t</code>) to keep track of the duplicated tiles.\n    <p class="Pp" id="should">Note that if this option is enabled, no guarantee\n        is made on the order in which tiles are output; while it\n        <a class="permalink" href="#should"><i class="Em">should</i></a> be\n        consistent across identical runs of a given\n        <code class="Nm">rgbgfx</code> release, the same is not true for\n        different releases.</p>\n  </dd>\n  <dt id="V"><a class="permalink" href="#V"><code class="Fl">-V</code></a>,\n    <code class="Fl">--version</code></dt>\n  <dd>Print the version of the program and exit.</dd>\n  <dt id="v"><a class="permalink" href="#v"><code class="Fl">-v</code></a>,\n    <code class="Fl">--verbose</code></dt>\n  <dd>Be verbose. The verbosity level is increased by one each time the flag is\n      specified, with each level including the previous:\n    <ol class="Bl-enum Bl-compact">\n      <li>Print the <code class="Nm">rgbgfx</code> configuration before taking\n          actions.</li>\n      <li>Print a notice before significant actions.</li>\n      <li>Print some of the actions\' intermediate results.</li>\n      <li>Print some internal debug information.</li>\n      <li>Print detailed internal information.</li>\n    </ol>\n    The verbosity level does not go past 6.\n    <p class="Pp">Note that verbose output is only intended to be consumed by\n        humans, and may change without notice between RGBDS releases; relying on\n        those for scripts is not advised.</p>\n  </dd>\n  <dt id="W"><a class="permalink" href="#W"><code class="Fl">-W</code></a>\n    <var class="Ar">warning</var>, <code class="Fl">--warning</code>\n    <var class="Ar">warning</var></dt>\n  <dd>Set warning flag <var class="Ar">warning</var>. A warning message will be\n      printed if <var class="Ar">warning</var> is an unknown warning flag. See\n      the <a class="Sx" href="#DIAGNOSTICS">DIAGNOSTICS</a> section for a list\n      of warnings.</dd>\n  <dt id="w"><a class="permalink" href="#w"><code class="Fl">-w</code></a></dt>\n  <dd>Disable all warning output, even when turned into errors.</dd>\n  <dt id="X"><a class="permalink" href="#X"><code class="Fl">-X</code></a>,\n    <code class="Fl">--mirror-x</code></dt>\n  <dd>Deduplicate tiles that are horizontally symmetrical mirror images of each\n      other across the X axis. Implies <code class="Fl">-u</code>.</dd>\n  <dt id="x"><a class="permalink" href="#x"><code class="Fl">-x</code></a>\n    <var class="Ar">quantity</var>, <code class="Fl">--trim-end</code>\n    <var class="Ar">quantity</var></dt>\n  <dd>Do not output the last <var class="Ar">quantity</var> tiles to the tile\n      data file; no other output is affected. This is useful for trimming\n      &#x201C;filler&#x201D; / blank squares at the end of an image. If fewer\n      than <var class="Ar">quantity</var> tiles would have been emitted, the\n      file will be empty.\n    <p class="Pp" id="after">Note that this is done\n        <a class="permalink" href="#after"><i class="Em">after</i></a>\n        deduplication if <code class="Fl">-u</code> was enabled, so you probably\n        don\'t want to use this option in combination with\n        <code class="Fl">-u</code>. Note also that the tiles that don\'t get\n        output will not count towards <code class="Fl">-N</code>\'s limit.</p>\n  </dd>\n  <dt id="Y"><a class="permalink" href="#Y"><code class="Fl">-Y</code></a>,\n    <code class="Fl">--mirror-y</code></dt>\n  <dd>Deduplicate tiles that are vertically symmetrical mirror images of each\n      other across the Y axis. Implies <code class="Fl">-u</code>.</dd>\n  <dt id="Z"><a class="permalink" href="#Z"><code class="Fl">-Z</code></a>,\n    <code class="Fl">--columns</code></dt>\n  <dd>Read squares from the PNG in column-major order (column by column),\n      instead of the default row-major order (line by line). This primarily\n      affects tile map and attribute map output, although it may also change\n      generated tile data and palettes.</dd>\n  <dt>@<var class="Ar">at_file</var></dt>\n  <dd>Read more options and arguments from a file, as if its contents were given\n      on the command line. Arguments are separated by whitespace or newlines.\n      Lines starting with a hash sign\n      (&#x2018;<code class="Li">#</code>&#x2019;) are considered comments and\n      ignored.\n    <p class="Pp" id="inside">No shell processing is performed, such as wildcard\n        or variable expansion. There is no support for escaping or quoting\n        whitespace to be included in arguments. The standard\n        &#x2018;<code class="Li">--</code>&#x2019; to stop option processing\n        also disables at-file processing. Note that while\n        &#x2018;<code class="Li">--</code>&#x2019; can be used\n        <a class="permalink" href="#inside"><i class="Em">inside</i></a> an\n        at-file, it only disables option processing within that at-file, and\n        processing continues in the parent scope.</p>\n    <p class="Pp">See <a class="Sx" href="#At_files">At-files</a> below for an\n        explanation of how this can be useful.</p>\n  </dd>\n</dl>\n<section class="Ss">\n<h3 class="Ss" id="At-files"><a class="permalink" href="#At-files">At-files</a></h3>\n<p class="Pp">In a given project, many images are to be converted with different\n    flags. The traditional way of solving this problem has been to specify the\n    different flags for each image in the Makefile or build script; this can be\n    inconvenient, as it centralizes all those flags away from the images they\n    concern.</p>\n<p class="Pp">To avoid these drawbacks, you can use &#x201C;at-files&#x201D;:\n    any command-line argument that begins with an at sign\n    (&#x2018;<code class="Li">@</code>&#x2019;) is interpreted as one, as\n    documented above. At-files can be stored right next to the corresponding\n    image, for example:</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbgfx -o image.2bpp -t\n  image.tilemap @image.flags image.png</code></div>\n<p class="Pp">This will read additional flags from the file\n    &#x2018;<code class="Li">image.flags</code>&#x2019;, which could contain,\n    for example, &#x2018;<code class="Li">-b 128</code>&#x2019; to specify a\n    base offset for the image\'s tiles. The above command could be generated from\n    the following\n    <a class="Xr" href="https://man7.org/linux/man-pages/man1/make.1.html">make(1)</a>\n    rule:</p>\n<div class="Bd Pp Bd-indent Li">\n<pre>%.2bpp %.tilemap: %.flags %.png\n        rgbgfx -o $*.2bpp -t $*.tilemap @$*.flags $*.png</pre>\n</div>\n</section>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="PALETTE_SPECIFICATION_FORMATS"><a class="permalink" href="#PALETTE_SPECIFICATION_FORMATS">PALETTE\n  SPECIFICATION FORMATS</a></h2>\n<p class="Pp">The following formats are supported:</p>\n<dl class="Bl-tag">\n  <dt id="act"><a class="permalink" href="#act"><code class="Cm">act</code></a></dt>\n  <dd><a class="Lk" href="https://www.adobe.com/devnet-apps/photoshop/fileformatashtml/#50577411_pgfId-1070626">Adobe\n      Photoshop color table</a>.</dd>\n  <dt id="aco"><a class="permalink" href="#aco"><code class="Cm">aco</code></a></dt>\n  <dd><a class="Lk" href="https://www.adobe.com/devnet-apps/photoshop/fileformatashtml/#50577411_pgfId-1055819">Adobe\n      Photoshop color swatch</a>.</dd>\n  <dt id="gbc"><a class="permalink" href="#gbc"><code class="Cm">gbc</code></a></dt>\n  <dd>A GBC palette memory dump, as emitted by <code class="Nm">rgbgfx</code>\n      <code class="Fl">-p</code>. Useful to force several images to share the\n      same palette.</dd>\n  <dt id="gpl"><a class="permalink" href="#gpl"><code class="Cm">gpl</code></a></dt>\n  <dd><a class="Lk" href="https://docs.gimp.org/2.10/en/gimp-concepts-palettes.html">GIMP\n      palette</a>.</dd>\n  <dt id="hex"><a class="permalink" href="#hex"><code class="Cm">hex</code></a></dt>\n  <dd>Plaintext lines of hexadecimal colors in\n      &#x2018;<code class="Li">rrggbb</code>&#x2019; format.</dd>\n  <dt id="png"><a class="permalink" href="#png"><code class="Cm">png</code></a></dt>\n  <dd>An image of square color swatches, with each row defining the colors for\n      one palette. Color swatches can be any square size.</dd>\n  <dt id="psp"><a class="permalink" href="#psp"><code class="Cm">psp</code></a></dt>\n  <dd><a class="Lk" href="https://www.selapa.net/swatches/colors/fileformats.php#psp_pal">Paint\n      Shop Pro palette</a>.</dd>\n</dl>\n<p class="Pp">If you wish for another format to be supported, please open an\n    issue (see <a class="Sx" href="#BUGS">BUGS</a> below) or contact us, and\n    supply a few sample files.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="PALETTE_GENERATION"><a class="permalink" href="#PALETTE_GENERATION">PALETTE\n  GENERATION</a></h2>\n<p class="Pp"><code class="Nm">rgbgfx</code> must generate palettes from the\n    colors in the input image, unless <code class="Fl">-c</code> was used; in\n    that case, the provided palettes will be used.\n    <a class="permalink" href="#If"><b class="Sy" id="If">If the order of colors\n    in the palettes is important to you</b></a>, for example because you want to\n    use palette swaps, please use <code class="Fl">-c</code> to specify the\n    palette explicitly.</p>\n<p class="Pp" id="any">First, if the image contains\n    <a class="permalink" href="#any"><i class="Em">any</i></a> transparent\n    pixel, color #0 of <i class="Em">all</i> palettes will be allocated to it.\n    This is done <a class="permalink" href="#even"><b class="Sy" id="even">even\n    if palettes were explicitly specified using</b></a>\n    <code class="Fl">-c</code>; then the specification only covers color #1\n    onwards. (If you do not want this, ask your image editor to remove the alpha\n    channel.)</p>\n<p class="Pp">After generating palettes, <code class="Nm">rgbgfx</code> sorts\n    colors within those palettes using the following rules:</p>\n<ul class="Bl-bullet Bd-indent">\n  <li>If the PNG file internally contains a palette (often dubbed an\n      &#x201C;indexed&#x201D; PNG), then colors in each output palette will be\n      sorted according to their order in the PNG\'s palette. Any unused entries\n      will be ignored, and only the first entry is considered if there are any\n      duplicates. (If you want a given color to appear more than once, or an\n      unused color to appear at all, you should specify the palettes explicitly\n      instead using <code class="Fl">-c</code>; <code class="Fl">-c</code>\n      <code class="Cm">embedded</code> may be appropriate.)</li>\n  <li>Otherwise, if the PNG only contains shades of gray, they will be\n      categorized into as many &#x201C;bins&#x201D; as there are colors per\n      palette, and the palette is set to these bins. The darkest gray will end\n      up in bin #0, and so on; note that this is the opposite of the RGB method\n      below. This is equivalent to having specified a DMG palette of\n      <code class="Fl">-c</code> <code class="Cm">dmg=E4</code>. If two distinct\n      grays end up in the same bin, the RGB method is used instead.\n    <p class="Pp" id="exactly">Be careful that <code class="Nm">rgbgfx</code> is\n        picky about what it considers &#x201C;grays&#x201D;: the red, green, and\n        blue components of each color must <i class="Em">all</i> be\n        <a class="permalink" href="#exactly"><i class="Em">exactly</i></a> the\n        same.</p>\n  </li>\n  <li>If none of the above apply, colors are sorted from lightest (first) to\n      darkest (last). The definition of luminance that\n      <code class="Nm">rgbgfx</code> uses is &#x201C;\n    <math class="eqn">\n      <mrow><mn>2126</mn><mo>&#x00D7;</mo><mi fontstyle="italic">red</mi><mo>+</mo><mn>7152</mn><mo>&#x00D7;</mo><mi fontstyle="italic">green</mi><mo>+</mo><mn>722</mn><mo>&#x00D7;</mo><mi fontstyle="italic">blue</mi></mrow>\n    </math>\n    &#x201D;.</li>\n</ul>\n<p class="Pp">Note that the &#x201C;indexed&#x201D; behavior depends on an\n    internal detail of how the PNG is saved, specifically its\n    &#x2018;<code class="Li">PLTE</code>&#x2019; chunk. Since few image editors\n    (such as GIMP) expose that detail, this behavior is only kept for\n    compatibility and should be considered deprecated.</p>\n<p class="Pp">It turns out that palette generation is an NP-complete problem\n    known as &quot;pagination&quot;, so <code class="Nm">rgbgfx</code> does not\n    attempt to find the optimal solution, but instead uses an\n    &quot;overload-and-remove&quot; heuristic to find a good one in a reasonable\n    amount of time. (There are no guarantees about how this algorithm will\n    generate palettes, apart from the constraints documented above.) It is\n    possible to compute the optimal solution externally (using a solver, for\n    example), and then provide it to <code class="Nm">rgbgfx</code> via\n    <code class="Fl">-c</code>.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="OUTPUT_FILES"><a class="permalink" href="#OUTPUT_FILES">OUTPUT\n  FILES</a></h2>\n<p class="Pp">All files output by <code class="Nm">rgbgfx</code> are binary\n    files, and designed to follow the Game Boy and Game Boy Color\'s native\n    formats. What follows is succinct descriptions of those formats, including\n    <code class="Nm">rgbgfx</code>-specific details. For more complete,\n    beginner-friendly descriptions of the native formats with illustrations,\n    please check out <a class="Lk" href="https://gbdev.io/pandocs/Graphics">Pan\n    Docs</a>.</p>\n<section class="Ss">\n<h3 class="Ss" id="Tile_data"><a class="permalink" href="#Tile_data">Tile\n  data</a></h3>\n<p class="Pp">Tile data is output like a binary dump of VRAM, with no padding\n    between tiles. Each tile is 16 bytes, 2 per row of 8 pixels; the bits of\n    color IDs are split into each byte (or &#x201C;bitplane&#x201D;). The\n    leftmost pixel\'s color ID is stored in the two bytes\' most significant bits,\n    and the rightmost pixel\'s color ID in their least significant bits.</p>\n<p class="Pp">When the bit depth (<code class="Fl">-d</code>) is set to 1, the\n    most significant bitplane (second byte) of each row, being all zeros, is\n    simply not output.</p>\n</section>\n<section class="Ss">\n<h3 class="Ss" id="Palette_data"><a class="permalink" href="#Palette_data">Palette\n  data</a></h3>\n<p class="Pp">Palette data is output like a dump of palette memory. Each color\n    is written as GBC-native little-endian RGB555, with the unused bit 15 set to\n    0. There is no padding between colors, nor between palettes; however, empty\n    colors in the palettes are output as 0xFFFF. For example, if 5 palettes are\n    generated with <code class="Fl">-s</code> <code class="Cm">4</code>, the\n    palette data file will be\n  <math class="eqn">\n    <mrow><mn>2</mn><mo>&#x00D7;</mo><mn>4</mn><mo>&#x00D7;</mo><mn>5</mn><mo>=</mo><mn>40</mn></mrow>\n  </math>\n   bytes long, even if some palettes contain less than 3 colors. Note that\n    <code class="Fl">-n</code> only caps how many palettes are generated (and\n    thus this file\'s size), but fewer may be generated still.</p>\n</section>\n<section class="Ss">\n<h3 class="Ss" id="Tile_map_data"><a class="permalink" href="#Tile_map_data">Tile\n  map data</a></h3>\n<p class="Pp">A tile map is an array of tile IDs, with one byte per tile ID. The\n    first byte always corresponds to the ID of the tile in top-left corner of\n    the input image; the second byte is either the ID of the tile to its right\n    (by default), or below it (with <code class="Fl">-Z</code>); and so on,\n    continuing in the same direction. Rows / columns (respectively) are stored\n    consecutively, with no padding.</p>\n</section>\n<section class="Ss">\n<h3 class="Ss" id="Attribute_map_data"><a class="permalink" href="#Attribute_map_data">Attribute\n  map data</a></h3>\n<p class="Pp">Attribute maps mirror the format of tile maps, like on the GBC,\n    especially the order in which bytes are output. The contents of individual\n    bytes follows the GBC\'s native format:</p>\n<table class="Bl-column">\n  <tr>\n    <td>Bit 7</td>\n    <td>BG-to-OAM Priority</td>\n    <td>Set to 0</td>\n  </tr>\n  <tr>\n    <td>Bit 6</td>\n    <td>Vertical Flip</td>\n    <td>0=Normal, 1=Mirror vertically</td>\n  </tr>\n  <tr>\n    <td>Bit 5</td>\n    <td>Horizontal Flip</td>\n    <td>0=Normal, 1=Mirror horizontally</td>\n  </tr>\n  <tr>\n    <td>Bit 4</td>\n    <td>Not used</td>\n    <td>Set to 0</td>\n  </tr>\n  <tr>\n    <td>Bit 3</td>\n    <td>Tile VRAM Bank number</td>\n    <td>0=Bank 0, 1=Bank 1</td>\n  </tr>\n  <tr>\n    <td>Bit 2&#x2013;0</td>\n    <td>Background Palette number</td>\n    <td>BGP0-7</td>\n  </tr>\n</table>\n<p class="Pp">Note that if more than 8 palettes are used, only the lowest 3 bits\n    of the palette ID are output.</p>\n</section>\n<section class="Ss">\n<h3 class="Ss" id="Automatic_output_paths"><a class="permalink" href="#Automatic_output_paths">Automatic\n  output paths</a></h3>\n<p class="Pp">For convenience, <code class="Nm">rgbgfx</code> provides shortcuts\n    to generate all files in the same directory. This is done by using the\n    uppercase version of a flag (for example, <code class="Fl">-A</code>\n    <span class="No">instead of</span> <code class="Fl">-a</code>). The\n    <var class="Ar">base_path</var> is the input image path (or the output tile\n    data path from <code class="Fl">-o</code>, <span class="No">if</span>\n    <code class="Fl">-O</code> <span class="No">was given</span>) with its\n    extension, if any, removed.</p>\n<p class="Pp">For example, these two commands are equivalent:</p>\n<div class="Bd Pp Bd-indent Li">\n<pre>$ rgbgfx img/player.png -o build/player.2bpp -P\n$ rgbgfx img/player.png -o build/player.2bpp -p img/player.pal</pre>\n</div>\n<p class="Pp">And so are these two:</p>\n<div class="Bd Pp Bd-indent Li">\n<pre>$ rgbgfx img/player.png -o build/player.2bpp -O -P\n$ rgbgfx img/player.png -o build/player.2bpp -p build/player.pal</pre>\n</div>\n</section>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="REVERSE_MODE"><a class="permalink" href="#REVERSE_MODE">REVERSE\n  MODE</a></h2>\n<p class="Pp"><code class="Nm">rgbgfx</code> can produce a PNG image from valid\n    data. This may be useful for ripping graphics, recovering lost source\n    images, etc. An important caveat on that last one, though: the conversion\n    process is\n    <a class="permalink" href="#lossy"><b class="Sy" id="lossy">lossy</b></a>\n    both ways, so the &#x201C;reversed&#x201D; image won\'t be perfectly\n    identical to the original&#x2014;but it should be close to a Game Boy\'s\n    output. (Keep in mind that many of consoles output different colors, so\n    there is no true reference rendering.)</p>\n<p class="Pp">When using reverse mode, make sure to pass the same flags that\n    were given when generating the data, especially <code class="Fl">-C</code>,\n    <code class="Fl">-d</code>, <code class="Fl">-N</code>,\n    <code class="Fl">-s</code>, <code class="Fl">-x</code>, and\n    <code class="Fl">-Z</code>.\n    &#x201C;<a class="Sx" href="#At_files">At-files</a>&#x201D; may help with\n    this. <code class="Nm">rgbgfx</code> will warn about any inconsistencies it\n    detects.</p>\n<p class="Pp">Files that are normally outputs (<code class="Fl">-a</code>,\n    <code class="Fl">-p</code>, <code class="Fl">-t</code>) become inputs, and\n    <var class="Ar">file</var> will be written to instead of read from, and thus\n    needs not exist beforehand. Any of these inputs not passed is assumed to be\n    some default:</p>\n<table class="Bl-column">\n  <tr>\n    <td>palettes</td>\n    <td>Unspecified palette data makes <code class="Nm">rgbgfx</code> assume DMG\n      (monochrome Game Boy) mode: a single palette of 4 grays. It is possible to\n      pass palettes using <code class="Fl">-c</code> instead of\n      <code class="Fl">-p</code>.</td>\n  </tr>\n  <tr>\n    <td>tile data</td>\n    <td>Tile data must be provided, as there is no reasonable assumption to fall\n      back on.</td>\n  </tr>\n  <tr>\n    <td>tile map</td>\n    <td>A missing tile map makes <code class="Nm">rgbgfx</code> assume that\n      tiles were not deduplicated, and should be laid out in the order they are\n      stored.</td>\n  </tr>\n  <tr>\n    <td>attribute map</td>\n    <td>Without an attribute map, <code class="Nm">rgbgfx</code> assumes that no\n      tiles were mirrored.</td>\n  </tr>\n</table>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="DIAGNOSTICS"><a class="permalink" href="#DIAGNOSTICS">DIAGNOSTICS</a></h2>\n<p class="Pp">Warnings are diagnostic messages that indicate possibly erroneous\n    behavior that does not necessarily compromise the conversion process. The\n    following options alter the way warnings are processed.</p>\n<dl class="Bl-tag">\n  <dt id="Werror"><a class="permalink" href="#Werror"><code class="Fl">-Werror</code></a></dt>\n  <dd>Make all warnings into errors. This can be negated as\n      <code class="Fl">-Wno-error</code> to prevent turning all warnings into\n      errors.</dd>\n  <dt id="Werror="><a class="permalink" href="#Werror="><code class="Fl">-Werror=</code></a></dt>\n  <dd>Make the specified warning or meta warning into an error. A warning\'s name\n      is appended (example: <code class="Fl">-Werror=obsolete</code>), and this\n      warning is implicitly enabled and turned into an error. This can be\n      negated as <code class="Fl">-Wno-error=</code> to prevent turning a\n      specified warning into an error, even if <code class="Fl">-Werror</code>\n      is in effect.</dd>\n</dl>\n<p class="Pp">The following warnings are &#x201C;meta&#x201D; warnings, that\n    enable a collection of other warnings. If a specific warning is toggled via\n    a meta flag and a specific one, the more specific one takes priority. The\n    position on the command-line acts as a tie breaker, the last one taking\n    effect.</p>\n<dl class="Bl-tag">\n  <dt id="Wall"><a class="permalink" href="#Wall"><code class="Fl">-Wall</code></a></dt>\n  <dd>This enables warnings that are likely to indicate an error or undesired\n      behavior, and that can easily be fixed.</dd>\n  <dt id="Weverything"><a class="permalink" href="#Weverything"><code class="Fl">-Weverything</code></a></dt>\n  <dd>Enables literally every warning.</dd>\n</dl>\n<p class="Pp">The following warnings are actual warning flags; with each\n    description, the corresponding warning flag is included. Note that each of\n    these flags also has a negation (for example,\n    <code class="Fl">-Wobsolete</code> enables the warning that\n    <code class="Fl">-Wno-obsolete</code> disables; and\n    <code class="Fl">-Wall</code> enables every warning that\n    <code class="Fl">-Wno-all</code> disables). Only the non-default flag is\n    listed here. Ignoring the &#x201C;no-&#x201D; prefix, entries are listed\n    alphabetically.</p>\n<dl class="Bl-tag">\n  <dt id="Wembedded"><a class="permalink" href="#Wembedded"><code class="Fl">-Wembedded</code></a></dt>\n  <dd>Warn when a generated palette is sorted according to the input PNG\'s\n      embedded palette but <code class="Fl">-c</code>\n      <code class="Cm">embedded</code> was not provided. This warning is enabled\n      by <code class="Fl">-Weverything</code>.</dd>\n  <dt id="Wno-obsolete"><a class="permalink" href="#Wno-obsolete"><code class="Fl">-Wno-obsolete</code></a></dt>\n  <dd>Warn when obsolete features are encountered, which have been deprecated\n      and may later be removed.</dd>\n  <dt id="Wtrim-nonempty"><a class="permalink" href="#Wtrim-nonempty"><code class="Fl">-Wtrim-nonempty</code></a></dt>\n  <dd>Warn when <code class="Fl">-x</code> trims a nonempty tile. An\n      &quot;empty&quot; tile uses entirely color 0 of its palette. This warning\n      is enabled by <code class="Fl">-Wall</code>.</dd>\n</dl>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="EXAMPLES"><a class="permalink" href="#EXAMPLES">EXAMPLES</a></h2>\n<p class="Pp">The following will only validate the\n    &#x2018;<code class="Li">tileset.png</code>&#x2019; image (check its size,\n    that all tiles have a suitable amount of colors, etc.), but output\n  nothing:</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbgfx\n  src/res/maps/overworld/tileset.png</code></div>\n<p class="Pp">The following will convert the\n    &#x2018;<code class="Li">tileset.png</code>&#x2019; image using the two\n    given palettes (and only those), and store the generated 2bpp tile data in\n    &#x2018;<code class="Li">tileset.2bpp</code>&#x2019;, and the attribute map\n    in &#x2018;<code class="Li">tileset.attrmap</code>&#x2019;.</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbgfx -c \'#ffffff,#8d05de,\n  #dc7905,#000000; #fff,#8d05de, #7e0000 , #000\' -A -o tileset.2bpp\n  tileset.png</code></div>\n<p class="Pp">The following will deduplicate the tiles in the\n    &#x2018;<code class="Li">title_screen.png</code>&#x2019; image, keeping only\n    one of each unique tile, and store the generated 2bpp tile data in\n    &#x2018;<code class="Li">title_screen.2bpp</code>&#x2019;, and the tile map\n    in &#x2018;<code class="Li">title_screen.tilemap</code>&#x2019;.</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbgfx -u title_screen.png -o\n  title_screen.2bpp -t title_screen.tilemap</code></div>\n<p class="Pp">The following will convert the given inline palette specification\n    to a palette set, and store the palette set in\n    &#x2018;<code class="Li">colors.pal</code>&#x2019;, without needing an input\n    image.</p>\n<p class="Pp"></p>\n<div class="Bd Bd-indent"><code class="Li">$ rgbgfx -c \'#fff,#ff0,#f80,#000\' -p\n  colors.pal</code></div>\n<p class="Pp">The following will convert two level images using the same\n    tileset, and error out if any of them contain tiles not in the tileset.</p>\n<div class="Bd Pp Bd-indent Li">\n<pre>$ rgbgfx tileset.png -o tileset.2bpp -O -P\n$ rgbgfx level1.png -i tileset.2bpp -c gbc:tileset.pal -t level1.tilemap -a level1.attrmap\n$ rgbgfx level2.png -i tileset.2bpp -c gbc:tileset.pal -t level2.tilemap -a level2.attrmap</pre>\n</div>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="BUGS"><a class="permalink" href="#BUGS">BUGS</a></h2>\n<p class="Pp">Please report bugs or mistakes in this documentation on\n    <a class="Lk" href="https://github.com/gbdev/rgbds/issues">GitHub</a>.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="SEE_ALSO"><a class="permalink" href="#SEE_ALSO">SEE\n  ALSO</a></h2>\n<p class="Pp"><a class="Xr" href="./rgbasm.1">rgbasm(1)</a>,\n    <a class="Xr" href="./rgblink.1">rgblink(1)</a>,\n    <a class="Xr" href="./rgbfix.1">rgbfix(1)</a>,\n    <a class="Xr" href="./rgbds.7">rgbds(7)</a></p>\n<p class="Pp">The Game Boy hardware reference\n    <a class="Lk" href="https://gbdev.io/pandocs/Graphics">Pan Docs</a>,\n    particularly the section about graphics.</p>\n</section>\n<section class="Sh">\n<h2 class="Sh" id="HISTORY"><a class="permalink" href="#HISTORY">HISTORY</a></h2>\n<p class="Pp"><code class="Nm">rgbgfx</code> was originally written by stag019\n    as a program to be packaged in RGBDS. It was later rewritten by\n    <span class="An">ISSOtm</span>, and is now maintained by a number of\n    contributors at\n    <a class="Lk" href="https://github.com/gbdev/rgbds">https://github.com/gbdev/rgbds</a>.</p>\n</section>\n',i={},c="rgbgfx(1) \u2014 Game Boy graphics converter",d={},r=[{value:"SYNOPSIS",id:"SYNOPSIS",level:2},{value:"DESCRIPTION",id:"DESCRIPTION",level:2},{value:"ARGUMENTS",id:"ARGUMENTS",level:2},{value:"At-files",id:"At-files",level:3},{value:"PALETTE SPECIFICATION FORMATS",id:"PALETTE_SPECIFICATION_FORMATS",level:2},{value:"PALETTE GENERATION",id:"PALETTE_GENERATION",level:2},{value:"OUTPUT FILES",id:"OUTPUT_FILES",level:2},{value:"Tile data",id:"Tile_data",level:3},{value:"Palette data",id:"Palette_data",level:3},{value:"Tile map data",id:"Tile_map_data",level:3},{value:"Attribute map data",id:"Attribute_map_data",level:3},{value:"Automatic output paths",id:"Automatic_output_paths",level:3},{value:"REVERSE MODE",id:"REVERSE_MODE",level:2},{value:"DIAGNOSTICS",id:"DIAGNOSTICS",level:2},{value:"EXAMPLES",id:"EXAMPLES",level:2},{value:"BUGS",id:"BUGS",level:2},{value:"SEE ALSO",id:"SEE_ALSO",level:2},{value:"HISTORY",id:"HISTORY",level:2}];function p(e){const a={h1:"h1",header:"header",...(0,o.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(a.header,{children:(0,n.jsx)(a.h1,{id:"rgbgfx1--game-boy-graphics-converter",children:"rgbgfx(1) \u2014 Game Boy graphics converter"})}),"\n","\n",(0,n.jsx)("div",{className:"manual-text",dangerouslySetInnerHTML:{__html:l}})]})}function h(e={}){const{wrapper:a}={...(0,o.R)(),...e.components};return a?(0,n.jsx)(a,{...e,children:(0,n.jsx)(p,{...e})}):p(e)}}}]);